const results = [];

// Geo-restriction patterns
const geoRestrictedPatterns = [
  /\bUS[\s-]?only\b/i, /\bUSA[\s-]?only\b/i, /\bUnited States[\s-]?only\b/i,
  /\bCanada[\s-]?only\b/i, /\bUK[\s-]?only\b/i, /\bUnited Kingdom[\s-]?only\b/i,
  /\bAustralia[\s-]?only\b/i, /\bEurope[\s-]?only\b/i, /\bEU[\s-]?only\b/i,
  /must (be |)(based|located|residing|reside|live) in (the )?(US|USA|United States|Canada|UK|Australia|Europe|EU)\b/i,
  /must be eligible to work in (the )?(US|USA|United States|Canada|UK|Australia)\b/i,
  /right to work in (the )?(US|USA|United States|Canada|UK|Australia)\b/i,
  /work authorization (in|for) (the )?(US|USA|United States|Canada|UK|Australia)\b/i,
  /authorized to work in (the )?(US|USA|United States|Canada|UK|Australia)\b/i,
  /\b(EST|CST|MST|PST|ET|CT|MT|PT)[\s-]?(only|required|timezone)\b/i,
  /US (time ?zones?|hours|business hours) only/i,
  /not available (in|for) (Saudi|Middle East|MENA|GCC)/i,
  /exclud(es?|ing) (Saudi|Middle East|MENA|GCC)/i,
];

const internationalSignals = [
  'worldwide', 'global', 'international', 'anywhere in the world',
  'work from anywhere', 'fully distributed', 'fully remote', 'all timezones',
  'timezone flexible', 'timezone agnostic', 'location independent',
  'emea', 'mena', 'middle east', 'saudi', 'gulf', 'apac', 'africa',
];

const titleExclusionPatterns = [
  /\bsenior\b/i, /\bsr\b\.?\s/i, /\blead\b/i, /\bstaff\b/i,
  /\bprincipal\b/i, /\bdirector\b/i, /\bvp\b/i, /\bvice president\b/i,
  /\bhead of\b/i, /\bproduct manager\b/i, /\bproduct owner\b/i,
  /\bproduct director\b/i, /\bproduct lead\b/i, /\bproduct designer\b/i,
  /\bsales\b/i, /\bios developer\b/i, /\bproduct analyst\b/i,
  /\bmarketing\b/i, /\bproduct specialist\b/i, /\bproduct strategist\b/i,
];

for (const item of $input.all()) {
  const job = item.json;
  const title = String(job.title || '').toLowerCase();
  const description = String(job.description || '').toLowerCase();
  const location = String(job.location || '').toLowerCase();
  const text = title + ' ' + description + ' ' + location;
  const fullText = (job.title || '') + ' ' + (job.description || '') + ' ' + (job.location || '');

  // Skip empty items from failed sources
  if (!job.title || job.title.trim() === '') continue;

  const isTitleExcluded = titleExclusionPatterns.some(p => p.test(job.title || ''));

  const remoteTerms = ['remote', 'work from home', 'wfh', 'anywhere', 'virtual', 'distributed', 'telehealth', 'home-based'];
  const isRemote = remoteTerms.some(t => text.includes(t));

  const isGeoRestricted = geoRestrictedPatterns.some(p => p.test(fullText));
  const hasInternationalSignal = internationalSignals.some(s => text.includes(s));
  const passesGeoCheck = !isGeoRestricted || hasInternationalSignal;

  const catA = ['ai training', 'data annotation', 'subject matter expert', 'sme', 'graphic design', 'video editor', 'medicine', 'medical expert', 'data entry', 'automation expert', 'n8n', 'ai arabic', 'prompt engineer', 'context engineer'];
  const catB = ['virtual assistant', 'full stack', 'frontend', 'backend', 'ui / ux', 'ui/ux', 'customer service', 'customer support'];
  let category = 'C';
  if (catA.some(w => text.includes(w))) category = 'A';
  else if (catB.some(w => text.includes(w))) category = 'B';

  results.push({ json: {
    title: job.title, company: job.company, apply_url: job.apply_url,
    description: job.description, location: job.location, salary: job.salary,
    is_remote: isRemote === true, is_geo_restricted: !passesGeoCheck,
    is_title_excluded: isTitleExcluded, Category: category,
  }});
}
return results;

return $input.all().filter(item => {
  const job = item.json;
  if (!job.title || job.title.trim() === '') return false;
  const isRemote = job.is_remote === true || job.is_remote === 'true';
  const isGeoRestricted = job.is_geo_restricted === true || job.is_geo_restricted === 'true';
  const isTitleExcluded = job.is_title_excluded === true || job.is_title_excluded === 'true';
  const category = job.Category ?? 'C';
  return isRemote && !isGeoRestricted && !isTitleExcluded && (category === 'A' || category === 'B');
});

