const item = $json;
let raw = item.description || '';

// 1. Convert block-level HTML to newlines
let clean = raw
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/(p|div|li|tr|h[1-6])>/gi, '\n')
  .replace(/<(ul|ol|table)[^>]*>/gi, '\n');

// 2. Strip ALL remaining HTML tags
clean = clean.replace(/<[^>]*>/g, '');

// 3. Decode HTML entities thoroughly
clean = clean
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&lt;/gi, '<')
  .replace(/&gt;/gi, '>')
  .replace(/&quot;/gi, '"')
  .replace(/&#39;/gi, "'")
  .replace(/&apos;/gi, "'")
  .replace(/&#x27;/gi, "'")
  .replace(/&#(\d+);/g, (m, d) => String.fromCharCode(parseInt(d, 10)))
  .replace(/&#x([0-9a-f]+);/gi, (m, h) => String.fromCharCode(parseInt(h, 16)))
  .replace(/&[a-zA-Z0-9#]+;/g, ' ');

// 4. Remove stray < > that Telegram rejects
clean = clean.replace(/[<>]/g, '');

// 5. Collapse whitespace
clean = clean.replace(/[ \t]+/g, ' ').replace(/\n{3,}/g, '\n\n').trim();

item.telegram_ready_desc = clean.substring(0, 3000);
item.description_plain = clean.substring(0, 1500);
return item;

// Jaabz returns HTML - extract job listings with multiple strategies
const html = String($input.first().json.data || $input.first().json || '');
const jobs = [];

// Strategy 1: Find job cards with title links
const cardPattern = /<a[^>]*href="(\/[^"]*\/(?:job|career|position|remote)[^"]*)"[^>]*class="[^"]*"[^>]*>\s*<h[2-4][^>]*>([^<]+)<\/h[2-4]>/gi;
let match;
while ((match = cardPattern.exec(html)) !== null) {
  jobs.push({
    json: {
      title: match[2].trim(),
      company: 'Unknown',
      location: 'Remote',
      description: '',
      apply_url: 'https://jaabz.com' + match[1],
      salary: '',
      is_remote: 'true',
      Category: '',
    },
  });
}

// Strategy 2: Try broader patterns if Strategy 1 found nothing
if (jobs.length === 0) {
  const linkPattern = /<a[^>]*href="(\/[^"]*\/[^"]*)"[^>]*>([^<]{3,80})<\/a>/gi;
  while ((match = linkPattern.exec(html)) !== null) {
    const title = match[2].replace(/<[^>]*>/g, '').trim();
    if (title.length > 5 && !/^(home|login|register|contact|about|blog|faq|pricing|terms|privacy)$/i.test(title)) {
      jobs.push({
        json: {
          title, company: 'Unknown', location: 'Remote', description: '',
          apply_url: match[1].startsWith('/') ? 'https://jaabz.com' + match[1] : match[1],
          salary: '', is_remote: 'true', Category: '',
        },
      });
    }
  }
}

// Strategy 3: Find any job title patterns in plain text
if (jobs.length === 0) {
  const text = html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  const titlePat = /(?:senior|junior|lead|staff|principal)?\s*(?:software|web|mobile|frontend|backend|full.?stack|devops|data|ml|ai|cloud)?\s*(?:engineer|developer|designer|architect|manager|analyst|scientist)/gi;
  while ((match = titlePat.exec(text)) !== null) {
    const t = match[0].trim();
    if (!jobs.find(j => j.json.title === t)) {
      jobs.push({ json: { title: t, company: 'Unknown', location: 'Remote', description: '', apply_url: 'https://jaabz.com/jobs/remote', salary: '', is_remote: 'true', Category: '' } });
    }
  }
}

if (jobs.length === 0) {
  return [{ json: { title: '', company: '', location: '', description: '', apply_url: '', salary: '', is_remote: 'false', Category: '' } }];
}
return jobs;

