// LinkedIn Guest API returns HTML with job cards
const html = String($input.first().json.data || $input.first().json || '');
const jobs = [];

// LinkedIn job cards are <li> elements with class containing "job"
const cardRegex = /<li[^>]*class="[^"]*job[^"]*"[^>]*>[\s\S]*?<\/li>/gi;
const cards = html.match(cardRegex) || [];

for (const card of cards) {
  // Extract title
  const titleMatch = card.match(/class="[^"]*title[^"]*"[^>]*>([^<]+)</i) ||
                     card.match(/<h3[^>]*>([^<]+)<\/h3>/i) ||
                     card.match(/<a[^>]*class="[^"]*job-title[^"]*"[^>]*>([^<]+)</i);
  // Extract company
  const companyMatch = card.match(/class="[^"]*company[^"]*"[^>]*>([^<]+)</i) ||
                       card.match(/class="[^"]*subtitle[^"]*"[^>]*>([^<]+)</i);
  // Extract location
  const locMatch = card.match(/class="[^"]*location[^"]*"[^>]*>([^<]+)</i);
  // Extract link
  const linkMatch = card.match(/href="(\/jobs\/[^"]*\?[^"]*)"/i) ||
                    card.match(/data-job-url="([^"]*)"/i);

  if (titleMatch) {
    const title = titleMatch[1].replace(/<[^>]*>/g, '').trim();
    jobs.push({ json: {
      title: title,
      company: companyMatch ? companyMatch[1].replace(/<[^>]*>/g, '').trim() : 'Unknown',
      location: locMatch ? locMatch[1].replace(/<[^>]*>/g, '').trim() : 'Remote',
      description: '',
      apply_url: linkMatch ? (linkMatch[1].startsWith('http') ? linkMatch[1] : 'https://www.linkedin.com' + linkMatch[1]) : 'https://www.linkedin.com/jobs/',
      salary: '',
      is_remote: 'true',
      Category: '',
    }});
  }
}

// Fallback: broader link matching
if (jobs.length === 0) {
  const linkPat = /href="(\/jobs\/view\/[^"]*)"[^>]*>([^<]{5,120})<\/a>/gi;
  let match;
  while ((match = linkPat.exec(html)) !== null) {
    jobs.push({ json: {
      title: match[2].replace(/<[^>]*>/g, '').trim(),
      company: 'Unknown', location: 'Remote', description: '',
      apply_url: 'https://www.linkedin.com' + match[1],
      salary: '', is_remote: 'true', Category: '',
    }});
  }
}

if (jobs.length === 0) {
  return [{ json: { title: '', company: '', location: '', description: '', apply_url: '', salary: '', is_remote: 'false', Category: '' } }];
}
return jobs;
